(window.webpackJsonp=window.webpackJsonp||[]).push([[305],{932:function(n,t){n.exports="\x3c!-- \ntitle: 05-React脚手架\nsort: \n--\x3e \n\n```bash\nsrc\n|_ App.css\n|_ App.js\n|_ index.js\n|_ App.js\n|_ App.js\n```\n\n## Sass\n\n> css扩展\n>\n> `Syntactically Awesome Style Sheets`\n\n```scss\nbody {\n\n    background: #343636;\n}\n\ndiv {\n    text-align: center;\n    \n    h1 {\n        color: aqua;\n    }\n\n    ul {\n        display: inline-block;\n    }\n}\n```\n\n> `App.js`\n\n```react\nimport React from 'react';\nimport './App.scss'\n\nclass App extends React.Component {\n  state = {\n    val: '',\n    list: []\n  }\n\n  handleChange = (event) => {\n    let val = event.target.value;\n    this.setState({ val })\n  }\n\n  handleAdd = (event) => {\n    let {val,list} = this.state;\n    list.push(val);\n    this.setState({list})\n  }\n\n  render() {\n    const { val,list } = this.state\n    return <div>\n      <h1>React Test</h1>\n      <input type=\"text\" val={val} onChange={this.handleChange} />\n      <button onClick={this.handleAdd}>Add</button>\n      <br></br>\n      <ul>\n        {\n          list.map(item =><li>{item}</li>)\n        }\n      </ul>\n    </div>\n  }\n}\n\nexport default App;\n```\n\n"}}]);